import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

interface ModelRow {
  name: string;
  rocAuc: number;
  f1: number;
  precision: number;
  recall: number;
}

interface ModelComparisonCardProps {
  baseline: ModelRow;
  gnn: ModelRow;
}

function MetricRow({ label, baselineVal, gnnVal }: { label: string; baselineVal: number; gnnVal: number }) {
  const gnnWins = gnnVal > baselineVal;
  return (
    <div className="grid grid-cols-3 text-sm py-1.5 border-b border-border last:border-0">
      <span className="text-muted-foreground">{label}</span>
      <span className="text-center">{baselineVal.toFixed(3)}</span>
      <span className={`text-center font-medium ${gnnWins ? "text-green-500" : "text-muted-foreground"}`}>
        {gnnVal.toFixed(3)}
      </span>
    </div>
  );
}

export function ModelComparisonCard({ baseline, gnn }: ModelComparisonCardProps) {
  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-sm font-medium">Model Comparison</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-3 text-xs text-muted-foreground pb-2 border-b border-border mb-1">
          <span>Metric</span>
          <span className="text-center">
            <Badge variant="outline" className="text-xs">{baseline.name}</Badge>
          </span>
          <span className="text-center">
            <Badge variant="secondary" className="text-xs">{gnn.name}</Badge>
          </span>
        </div>
        <MetricRow label="ROC-AUC" baselineVal={baseline.rocAuc} gnnVal={gnn.rocAuc} />
        <MetricRow label="F1" baselineVal={baseline.f1} gnnVal={gnn.f1} />
        <MetricRow label="Precision" baselineVal={baseline.precision} gnnVal={gnn.precision} />
        <MetricRow label="Recall" baselineVal={baseline.recall} gnnVal={gnn.recall} />
      </CardContent>
    </Card>
  );
}

