// FraudGraph renders the interactive Cytoscape.js transaction graph.
//
// IMPORTANT: Cytoscape.js accesses the DOM directly and cannot run server-side.
// This component must remain a Client Component ("use client").
// When implementing full Cytoscape logic in Phase 2, use:
//   import dynamic from "next/dynamic"
//   const CytoscapeComponent = dynamic(() => import("react-cytoscapejs"), { ssr: false })
//
// Phase 1: placeholder only — no Cytoscape logic yet.

import { TransactionNode } from "@/lib/types/graph";
import { Network } from "lucide-react";

interface FraudGraphProps {
  selectedNodeId?: string | null;
  onNodeSelect?: (node: TransactionNode | null) => void;
}

export function FraudGraph({ onNodeSelect }: FraudGraphProps) {
  return (
    <div className="w-full h-full min-h-[400px] flex flex-col items-center justify-center bg-muted/30 rounded-lg border border-dashed border-border">
      <Network className="h-12 w-12 text-muted-foreground/40 mb-3" />
      <p className="text-sm font-medium text-muted-foreground">Transaction Graph</p>
      <p className="text-xs text-muted-foreground/60 mt-1 text-center max-w-xs">
