        <br />
        Nodes = Bitcoin transactions · Edges = transaction flow
      </p>
      <button
        className="mt-4 text-xs text-blue-500 underline"
        onClick={() => onNodeSelect?.({
          id: "tx_demo",
          label: "Transaction demo",
          trueLabel: "illicit",
          predictedLabel: "illicit",
          riskLevel: "high",
          fraudProbability: 0.91,
          timeStep: 32,
          degree: 14,
          inDegree: 5,
          outDegree: 9,
          knownLabel: true,
        })}
      >
        Simulate node click (demo)
      </button>
    </div>
  );
}

