// Temporary deterministic generator for mock Elliptic-style graph data.
// Run with: node /tmp/gen_mock.js  — outputs into public/data/.
const fs = require("fs");
const path = require("path");

const OUT = path.join(process.argv[2], "public", "data");

// Seeded RNG (mulberry32) for reproducible output
let seed = 20260531;
function rng() {
  seed |= 0; seed = (seed + 0x6D2B79F5) | 0;
  let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
}
const pick = (arr) => arr[Math.floor(rng() * arr.length)];
const randInt = (a, b) => a + Math.floor(rng() * (b - a + 1));
const round = (n, d = 3) => Number(n.toFixed(d));

const N = 72;
const riskFromProb = (p) => (p < 0.4 ? "low" : p < 0.75 ? "medium" : "high");

// ── Nodes ──
const nodes = [];
for (let i = 1; i <= N; i++) {
  const id = `tx_${String(i).padStart(5, "0")}`;
  const r = rng();
  let classLabel;
  if (r < 0.17) classLabel = "illicit";
  else if (r < 0.47) classLabel = "licit";
  else classLabel = "unknown";

  let prob;
  if (classLabel === "illicit") prob = 0.6 + rng() * 0.38;
  else if (classLabel === "licit") prob = 0.02 + rng() * 0.33;
  else prob = 0.1 + rng() * 0.85;
  prob = round(prob);

  const riskLevel = riskFromProb(prob);
  const predictedLabel = prob >= 0.5 ? "illicit" : "licit";
  const knownLabel = classLabel !== "unknown";
  const gnnProbability = prob;
  let baselineProbability = round(Math.max(0.01, Math.min(0.99, prob + (rng() - 0.5) * 0.3)));

  nodes.push({
    id,
    label: `Transaction ${String(i).padStart(5, "0")}`,
    timeStep: randInt(1, 49),
    classLabel,
    predictedLabel,
    fraudProbability: prob,
    riskLevel,
    knownLabel,
    baselineProbability,
    gnnProbability,
    featureSummary: {
      inputs: randInt(1, 12),
      outputs: randInt(1, 10),
      totalValueBtc: round(rng() * 50, 4),
      feeBtc: round(rng() * 0.01, 5),
    },
  });
}

// ── Edges (directed transaction flow) ──
const edges = [];
const seen = new Set();
let e = 0;
for (let i = 1; i < N; i++) {
  const links = randInt(1, 3);
  for (let k = 0; k < links; k++) {
    // connect to an earlier or nearby node to form a flow
    let j = randInt(Math.max(1, i - 8), i);
    if (j === i) j = randInt(1, i);
    const src = nodes[i].id;
    const tgt = nodes[j - 1].id;
    const key = `${src}->${tgt}`;
    if (src === tgt || seen.has(key)) continue;
    seen.add(key);
    edges.push({
      id: `edge_${String(++e).padStart(5, "0")}`,
      source: src,
      target: tgt,
      type: "transaction_flow",
      directed: true,
    });
  }
}

// ── Degrees ──
const inDeg = {}, outDeg = {};
nodes.forEach((n) => { inDeg[n.id] = 0; outDeg[n.id] = 0; });
edges.forEach((ed) => { outDeg[ed.source]++; inDeg[ed.target]++; });
nodes.forEach((n) => {
  n.inDegree = inDeg[n.id];
  n.outDegree = outDeg[n.id];
  n.degree = inDeg[n.id] + outDeg[n.id];
});

// ── Predictions ──
const predictions = nodes.map((n) => ({
  nodeId: n.id,
  trueLabel: n.classLabel,
  predictedLabel: n.predictedLabel,
  fraudProbability: n.fraudProbability,
  riskLevel: n.riskLevel,
  timeStep: n.timeStep,
  knownLabel: n.knownLabel,
  baselineProbability: n.baselineProbability,
  gnnProbability: n.gnnProbability,
}));

// ── Explanations ──
const explanations = nodes.map((n) => {
  const bullets = [];
  if (n.riskLevel === "high")
    bullets.push("The model predicts a high illicit probability for this transaction.");
  else if (n.riskLevel === "medium")
    bullets.push("The model predicts a moderate illicit probability for this transaction.");
  else
    bullets.push("The model predicts a low illicit probability for this transaction.");

  if (!n.knownLabel)
    bullets.push("This transaction is unlabeled in the original dataset (unknown — not confirmed safe).");
  else
    bullets.push(`This transaction has a known ground-truth label: ${n.classLabel}.`);

  if (n.inDegree + n.outDegree >= 6)
    bullets.push(`It has a relatively high connectivity (in-degree ${n.inDegree}, out-degree ${n.outDegree}).`);
  if (Math.abs(n.gnnProbability - n.baselineProbability) >= 0.2)
    bullets.push("The GNN and the baseline model disagree noticeably on this transaction.");
  bullets.push(`It appears in time step ${n.timeStep}.`);
  return { nodeId: n.id, bullets };
});

// ── Metrics (mock, clearly illustrative) ──
const metrics = {
  baseline: {
    name: "Logistic Regression",
    rocAuc: 0.891, f1: 0.681, precision: 0.724, recall: 0.643,
    precisionAtK: { k50: 0.78, k100: 0.71, k500: 0.55 },
    confusionMatrix: { truePositive: 612, falsePositive: 233, trueNegative: 4021, falseNegative: 340 },
  },
  gnn: {
    name: "GraphSAGE",
    rocAuc: 0.964, f1: 0.823, precision: 0.881, recall: 0.772,
    precisionAtK: { k50: 0.94, k100: 0.89, k500: 0.71 },
