import {
  TransactionNode,
  TransactionEdge,
  TransactionLabel,
  PredictionLabel,
  RiskLevel,
  FeatureSummary,
  NodeExplanation,
} from "@/lib/types/graph";
import { MetricsData } from "@/lib/types/metrics";

// Raw node shape as stored in public/data/nodes.json (uses `classLabel`).
interface RawNode {
  id: string;
  label: string;
  timeStep: number;
  classLabel: TransactionLabel;
  predictedLabel: PredictionLabel;
  fraudProbability: number;
  riskLevel: RiskLevel;
  knownLabel: boolean;
  baselineProbability?: number;
  gnnProbability?: number;
  degree?: number;
  inDegree?: number;
  outDegree?: number;
  featureSummary?: FeatureSummary;
}

async function fetchJson<T>(file: string): Promise<T> {
  const res = await fetch(`/data/${file}`, { cache: "force-cache" });
  if (!res.ok) {
    throw new Error(`Failed to load /data/${file} (${res.status})`);
  }
  return (await res.json()) as T;
}

// Normalize raw nodes: classLabel -> trueLabel (per shared TransactionNode type).
function normalizeNode(raw: RawNode): TransactionNode {
  return {
    id: raw.id,
    label: raw.label,
    trueLabel: raw.classLabel,
    predictedLabel: raw.predictedLabel,
    riskLevel: raw.riskLevel,
    fraudProbability: raw.fraudProbability,
    timeStep: raw.timeStep,
    degree: raw.degree,
    inDegree: raw.inDegree,
    outDegree: raw.outDegree,
    knownLabel: raw.knownLabel,
    baselineProbability: raw.baselineProbability,
    gnnProbability: raw.gnnProbability,
    featureSummary: raw.featureSummary,
  };
}

export async function loadGraphData(): Promise<{
  nodes: TransactionNode[];
  edges: TransactionEdge[];
}> {
  const [rawNodes, edges] = await Promise.all([
    fetchJson<RawNode[]>("nodes.json"),
    fetchJson<TransactionEdge[]>("edges.json"),
  ]);
  return { nodes: rawNodes.map(normalizeNode), edges };
}

export function loadMetrics(): Promise<MetricsData> {
  return fetchJson<MetricsData>("metrics.json");
}

export function loadExplanations(): Promise<NodeExplanation[]> {
  return fetchJson<NodeExplanation[]>("explanations.json");
}

