"use client";

import { useEffect, useMemo, useState } from "react";
import { AppHeader } from "@/components/layout/AppHeader";
import { MetricCard } from "@/components/metrics/MetricCard";
import { ModelComparisonCard } from "@/components/metrics/ModelComparisonCard";
import { RiskDistributionChart } from "@/components/metrics/RiskDistributionChart";
import { ClusterSummaryCard } from "@/components/metrics/ClusterSummaryCard";
import { FraudGraph } from "@/components/graph/FraudGraph";
import { GraphErrorBoundary } from "@/components/graph/GraphErrorBoundary";
import { GraphFilters } from "@/components/graph/GraphFilters";
import { GraphLegend } from "@/components/graph/GraphLegend";
import { NodeDetailPanel } from "@/components/graph/NodeDetailPanel";
import { SimulationPanel } from "@/components/simulation/SimulationPanel";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { ShieldAlert, Network, Activity, Clock, Loader2, AlertTriangle } from "lucide-react";

import { TransactionNode, TransactionEdge } from "@/lib/types/graph";
import { MetricsData } from "@/lib/types/metrics";
import { loadGraphData, loadMetrics, loadExplanations } from "@/lib/data/loadGraphData";
import { buildCytoscapeElements } from "@/lib/graph/buildCytoscapeElements";
import { filterGraph, DashboardFilters, DEFAULT_FILTERS } from "@/lib/graph/filterGraph";

const LABEL_VARIANT: Record<string, "destructive" | "secondary" | "outline"> = {
  illicit: "destructive",
  licit: "secondary",
  unknown: "outline",
};

export default function DashboardPage() {
  const [nodes, setNodes] = useState<TransactionNode[]>([]);
  const [edges, setEdges] = useState<TransactionEdge[]>([]);
  const [metrics, setMetrics] = useState<MetricsData | null>(null);
  const [explanations, setExplanations] = useState<Record<string, string[]>>({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [filters, setFilters] = useState<DashboardFilters>(DEFAULT_FILTERS);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  useEffect(() => {
    let active = true;
    (async () => {
      try {
        const [graph, m, expl] = await Promise.all([
          loadGraphData(),
          loadMetrics(),
          loadExplanations(),
        ]);
        if (!active) return;
        setNodes(graph.nodes);
        setEdges(graph.edges);
        setMetrics(m);
        setExplanations(Object.fromEntries(expl.map((e) => [e.nodeId, e.bullets])));
      } catch (e) {
        if (active) setError(e instanceof Error ? e.message : "Failed to load graph data.");
      } finally {
        if (active) setLoading(false);
      }
    })();
    return () => {
      active = false;
    };
  }, []);

  const timeSteps = useMemo(
    () => Array.from(new Set(nodes.map((n) => n.timeStep).filter((t): t is number => t !== undefined))).sort((a, b) => a - b),
    [nodes]
  );

  const filtered = useMemo(() => filterGraph(nodes, edges, filters), [nodes, edges, filters]);
  const elements = useMemo(
    () => buildCytoscapeElements(filtered.nodes, filtered.edges),
    [filtered]
  );

  const selectedNode = useMemo(
    () => nodes.find((n) => n.id === selectedNodeId) ?? null,
    [nodes, selectedNodeId]
  );

  // Derived metrics from the loaded sample
  const riskDist = useMemo(() => {
    const counts = { low: 0, medium: 0, high: 0 };
    nodes.forEach((n) => counts[n.riskLevel]++);
    return [
      { riskLevel: "low", count: counts.low },
      { riskLevel: "medium", count: counts.medium },
      { riskLevel: "high", count: counts.high },
    ];
  }, [nodes]);

  const summary = useMemo(() => {
    const s = { illicit: 0, licit: 0, unknown: 0, high: 0 };
    nodes.forEach((n) => {
      s[n.trueLabel]++;
      if (n.riskLevel === "high") s.high++;
    });
    return s;
  }, [nodes]);

  const topSuspicious = useMemo(
    () => [...nodes].sort((a, b) => b.fraudProbability - a.fraudProbability).slice(0, 8),
    [nodes]
  );

  // ── Loading / error states ──
  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <AppHeader />
        <div className="flex flex-col items-center justify-center py-40 text-muted-foreground">
          <Loader2 className="h-6 w-6 animate-spin mb-3" />
          <p className="text-sm">Loading transaction graph…</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-background">
        <AppHeader />
        <div className="flex flex-col items-center justify-center py-40 text-muted-foreground">
          <AlertTriangle className="h-6 w-6 text-amber-500 mb-3" />
          <p className="text-sm font-medium text-foreground">Could not load dashboard data</p>
          <p className="text-xs mt-1">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <AppHeader />

      <main className="max-w-screen-2xl mx-auto px-4 py-6 space-y-6">

        {/* Top metric cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <MetricCard title="Total Transactions" value={nodes.length} subtitle="Graph sample" icon={Network} />
          <MetricCard title="High-Risk Nodes" value={summary.high} subtitle="Predicted illicit prob ≥ 0.75" icon={ShieldAlert} />
          <MetricCard title="GNN ROC-AUC" value={metrics ? metrics.gnn.rocAuc.toFixed(3) : "—"} subtitle={metrics?.gnn.name} icon={Activity} />
          <MetricCard title="Time Steps" value={timeSteps.length} subtitle="In this sample" icon={Clock} />
        </div>

        {/* Main grid: filters | graph | node detail */}
        <div className="grid grid-cols-12 gap-4">
          <div className="col-span-12 md:col-span-3 space-y-4">
            <GraphFilters filters={filters} onChange={setFilters} timeSteps={timeSteps} />
            <ClusterSummaryCard
              totalNodes={nodes.length}
              illicitCount={summary.illicit}
              licitCount={summary.licit}
              unknownCount={summary.unknown}
              highRiskCount={summary.high}
            />
          </div>

          <div className="col-span-12 md:col-span-6 space-y-2">
            <div className="h-[440px]">
              <GraphErrorBoundary>
                <FraudGraph
                  elements={elements}
                  selectedNodeId={selectedNodeId}
                  onNodeSelect={setSelectedNodeId}
                />
              </GraphErrorBoundary>
            </div>
            <p className="text-xs text-muted-foreground">
              Showing {filtered.nodes.length} of {nodes.length} transactions · {filtered.edges.length} flow edges
            </p>
            <GraphLegend />
          </div>

          <div className="col-span-12 md:col-span-3">
            <NodeDetailPanel
              node={selectedNode}
              explanation={selectedNode ? explanations[selectedNode.id] : undefined}
            />
          </div>
        </div>

        {/* Bottom row */}
        <div className="grid grid-cols-12 gap-4">
          <div className="col-span-12 md:col-span-4">
            {metrics && <ModelComparisonCard baseline={metrics.baseline} gnn={metrics.gnn} />}
          </div>
          <div className="col-span-12 md:col-span-4">
            <RiskDistributionChart data={riskDist} />
          </div>
          <div className="col-span-12 md:col-span-4">
            <SimulationPanel />
          </div>
        </div>

        {/* Top suspicious table */}
        <div>
          <h2 className="text-sm font-semibold mb-3">Top Suspicious Transactions</h2>
          <div className="rounded-md border border-border overflow-hidden">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="text-xs">Transaction ID</TableHead>
                  <TableHead className="text-xs">Fraud Probability</TableHead>
                  <TableHead className="text-xs">Risk Level</TableHead>
                  <TableHead className="text-xs">True Label</TableHead>
                  <TableHead className="text-xs">Time Step</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {topSuspicious.map((row) => (
                  <TableRow
                    key={row.id}
                    className={`text-xs cursor-pointer ${selectedNodeId === row.id ? "bg-muted/50" : ""}`}
                    onClick={() => setSelectedNodeId(row.id)}
                  >
                    <TableCell className="font-mono">{row.id}</TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <div className="h-1.5 rounded-full bg-red-500" style={{ width: `${row.fraudProbability * 60}px` }} />
                        {(row.fraudProbability * 100).toFixed(0)}%
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant={row.riskLevel === "high" ? "destructive" : row.riskLevel === "medium" ? "outline" : "secondary"} className="text-xs">
                        {row.riskLevel}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant={LABEL_VARIANT[row.trueLabel]} className="text-xs">
                        {row.trueLabel}
                      </Badge>
                    </TableCell>
                    <TableCell>{row.timeStep}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </div>

      </main>
    </div>
  );
}

