import { AmountCategory, SimulationResult } from "@/lib/types/simulation";

const clamp = (n: number) => Math.max(0, Math.min(1, n));
const AMOUNT_WEIGHT: Record<AmountCategory, number> = { low: 0.3, medium: 0.6, high: 1.0 };

function riskLevel(p: number): SimulationResult["riskLevel"] {
  return p >= 0.75 ? "high" : p >= 0.4 ? "medium" : "low";
}

interface SimInput {
  neighborProbabilities: number[]; // GNN risk of connected nodes
  illicitLabeledNeighbors: number;
  unknownNeighbors: number;
  timeStepRiskFactor: number; // 0–1, general risk of the chosen time step
  amountCategory: AmountCategory;
}

// Lightweight what-if heuristic — NOT a retrained GNN. Mirrors the documented
// formula: weighted blend of neighbour risk signals.
export function calculateSimulatedRisk(input: SimInput): Omit<SimulationResult, "simulatedNodeId"> {
  const { neighborProbabilities: p, illicitLabeledNeighbors, unknownNeighbors, timeStepRiskFactor, amountCategory } = input;
  const n = p.length;

  const averageNeighborRisk = n ? p.reduce((a, b) => a + b, 0) / n : 0;
  const highRiskNeighborRatio = n ? p.filter((v) => v >= 0.75).length / n : 0;
  const predictedIllicitNeighborRatio = n ? p.filter((v) => v >= 0.5).length / n : 0;
  const degreeGrowthFactor = clamp(0.5 * Math.min(1, n / 8) + 0.5 * AMOUNT_WEIGHT[amountCategory]);

  const score = clamp(
    0.45 * averageNeighborRisk +
      0.25 * highRiskNeighborRatio +
      0.15 * predictedIllicitNeighborRatio +
      0.1 * timeStepRiskFactor +
      0.05 * degreeGrowthFactor
  );
  const level = riskLevel(score);

  const explanation: string[] = [
    `Connected to ${n} transaction${n === 1 ? "" : "s"}; ${p.filter((v) => v >= 0.75).length} are high-risk.`,
    `Average neighbour GraphSAGE risk is ${(averageNeighborRisk * 100).toFixed(0)}%.`,
  ];
  if (illicitLabeledNeighbors > 0)
    explanation.push(`Connected to ${illicitLabeledNeighbors} known illicit-labeled transaction(s).`);
  if (unknownNeighbors > 0)
    explanation.push(`${unknownNeighbors} connected transaction(s) are unlabeled (unknown — not confirmed safe).`);
  explanation.push(`The simulated transaction falls in the ${level}-risk range.`);
  explanation.push("This is a heuristic what-if score, not retrained GraphSAGE inference.");

  return { simulatedRiskScore: Number(score.toFixed(4)), riskLevel: level, explanation };
}

