import { getGraphData } from "@/lib/data/getGraphData";
import { calculateSimulatedRisk } from "@/lib/simulation/calculateSimulatedRisk";
import { AmountCategory } from "@/lib/types/simulation";

export async function POST(req: Request) {
  let body: { connectToNodeIds?: string[]; timeStep?: number; amountCategory?: AmountCategory };
  try {
    body = await req.json();
  } catch {
    return Response.json(
      { success: false, error: { message: "Invalid request body.", code: "BAD_REQUEST" } },
      { status: 400 }
    );
  }

  const ids = body.connectToNodeIds ?? [];
  const amountCategory: AmountCategory = body.amountCategory ?? "medium";
  if (!Array.isArray(ids) || ids.length === 0) {
    return Response.json(
      { success: false, error: { message: "Select at least one transaction to connect to.", code: "NO_CONNECTIONS" } },
      { status: 400 }
    );
  }

  try {
    const { nodes } = await getGraphData();
    const byId = new Map(nodes.map((n) => [n.id, n]));
    const neighbors = ids.map((id) => byId.get(id)).filter((n): n is NonNullable<typeof n> => Boolean(n));

    const neighborProbabilities = neighbors.map((n) => n.gnnProbability ?? n.fraudProbability);
    const illicitLabeledNeighbors = neighbors.filter((n) => n.trueLabel === "illicit").length;
    const unknownNeighbors = neighbors.filter((n) => n.trueLabel === "unknown").length;

    // Time-step risk = average primary risk of nodes in the requested time step.
    const ts = body.timeStep;
    const inStep = ts != null ? nodes.filter((n) => n.timeStep === ts) : [];
    const timeStepRiskFactor = inStep.length
      ? inStep.reduce((a, n) => a + (n.gnnProbability ?? n.fraudProbability), 0) / inStep.length
      : 0.5;

    const result = calculateSimulatedRisk({
      neighborProbabilities,
      illicitLabeledNeighbors,
      unknownNeighbors,
      timeStepRiskFactor,
      amountCategory,
    });

    return Response.json({ success: true, data: { simulatedNodeId: "sim_tx_001", ...result } });
  } catch {
    return Response.json(
      { success: false, error: { message: "Simulation failed.", code: "SIMULATION_ERROR" } },
      { status: 500 }
    );
  }
}

