"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { FlaskConical, Plus, X, Loader2 } from "lucide-react";
import { AmountCategory, SimulationResult } from "@/lib/types/simulation";
import { ApiResponse } from "@/lib/types/api";

const AMOUNTS: AmountCategory[] = ["low", "medium", "high"];
const RISK_BADGE: Record<string, "destructive" | "outline" | "secondary"> = {
  high: "destructive",
  medium: "outline",
  low: "secondary",
};

export function SimulationPanel({ selectedNodeId }: { selectedNodeId: string | null }) {
  const [connections, setConnections] = useState<string[]>([]);
  const [amount, setAmount] = useState<AmountCategory>("medium");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<SimulationResult | null>(null);

  const addSelected = () => {
    if (selectedNodeId && !connections.includes(selectedNodeId)) {
      setConnections([...connections, selectedNodeId]);
    }
  };

  const run = async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const res = await fetch("/api/simulate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ connectToNodeIds: connections, timeStep: 49, amountCategory: amount }),
      });
      const body = (await res.json()) as ApiResponse<SimulationResult>;
      if (!body.success) throw new Error(body.error.message);
      setResult(body.data);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Simulation failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="text-sm font-medium flex items-center gap-2">
          <FlaskConical className="h-4 w-4" />
          Simulation Mode
          <Badge variant="outline" className="text-xs ml-auto">What-if</Badge>
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-3 text-xs">
        <p className="text-muted-foreground">
          Inject a hypothetical transaction connected to selected transactions and estimate its risk
          from neighbour signals. This is a heuristic — it does <strong>not</strong> retrain GraphSAGE.
        </p>

        <div>
          <div className="flex items-center justify-between mb-1.5">
            <p className="font-medium text-foreground">Connections ({connections.length})</p>
            <button
              onClick={addSelected}
              disabled={!selectedNodeId}
              className="text-xs text-blue-500 hover:underline disabled:text-muted-foreground/40 flex items-center gap-1"
            >
              <Plus className="h-3 w-3" /> Add selected
            </button>
          </div>
          {connections.length === 0 ? (
            <p className="text-muted-foreground/60">Select a node in the graph, then “Add selected”.</p>
          ) : (
            <div className="flex flex-wrap gap-1.5">
              {connections.map((id) => (
                <Badge key={id} variant="secondary" className="text-xs font-mono gap-1">
                  {id.replace(/^tx_/, "")}
                  <button onClick={() => setConnections(connections.filter((c) => c !== id))}>
                    <X className="h-3 w-3" />
                  </button>
                </Badge>
              ))}
            </div>
          )}
        </div>

        <div>
          <p className="font-medium text-foreground mb-1">Amount Category</p>
          <div className="flex gap-1.5">
            {AMOUNTS.map((a) => (
              <Badge
                key={a}
                variant={a === amount ? (a === "high" ? "destructive" : "secondary") : "outline"}
                className={`cursor-pointer text-xs capitalize ${a === amount ? "" : "opacity-50"}`}
                onClick={() => setAmount(a)}
              >
                {a}
              </Badge>
            ))}
          </div>
        </div>

        <Button size="sm" className="w-full text-xs" onClick={run} disabled={loading || connections.length === 0}>
          {loading ? <Loader2 className="h-3 w-3 animate-spin" /> : "Run Simulation"}
        </Button>

        {error && <p className="text-xs text-amber-500">{error}</p>}

        {result && (
          <div className="border border-border rounded-md p-2 bg-muted/30 space-y-1.5">
            <div className="flex justify-between">
              <span className="text-muted-foreground">Simulated Risk Score</span>
              <span className="font-medium">{(result.simulatedRiskScore * 100).toFixed(0)}%</span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-muted-foreground">Risk Level</span>
              <Badge variant={RISK_BADGE[result.riskLevel]} className="text-xs">{result.riskLevel}</Badge>
            </div>
            <ul className="text-muted-foreground/70 space-y-0.5 pt-1">
              {result.explanation.map((b, i) => (
                <li key={i}>• {b}</li>
              ))}
            </ul>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

